SELECT DISTINCT ?player
WHERE {
  ?game wdt:P585 ?date ;
        wdt:P1346 ?winnerTeam .
  FILTER (YEAR(?date) >= 2016 && YEAR(?date) <= 2023)
  ?player wdt:P54 ?winnerTeam .
  ?player wdt:P54 ?currentTeam .
  ?currentTeam wdt:P118 wd:Q1413717 .
}

